const apps = $input.all().map(item => item.json);
const n = apps.length;
const MIN_N = 5;
const minNReached = n >= MIN_N;

const now = new Date();
// Sunday 7pm trigger -> week_start = Monday of the week ending today
const weekStart = new Date(now);
weekStart.setDate(weekStart.getDate() - 6);
const weekStartStr = weekStart.toISOString().slice(0, 10);
const todayStr = now.toISOString().slice(0, 10);

const RESPONDED_STATUSES = ['responded', 'interview'];

function pct(num, den) {
  if (den === 0) return 'n/a';
  return `${num}/${den} (${Math.round((num / den) * 100)}%)`;
}

// Status breakdown
const statusCounts = {};
for (const a of apps) {
  statusCounts[a.status] = (statusCounts[a.status] || 0) + 1;
}
const statusLines = Object.entries(statusCounts)
  .map(([status, count]) => `  ${status}: ${count}`)
  .join('\n') || '  (none)';

// Match score stats
const scored = apps.filter(a => a.match_score != null);
const avgScore = scored.length > 0
  ? Math.round(scored.reduce((sum, a) => sum + a.match_score, 0) / scored.length)
  : null;

// By match tier
const byTier = {};
for (const a of apps) {
  const tier = a.match_tier || 'unknown';
  if (!byTier[tier]) byTier[tier] = { total: 0, responded: 0 };
  byTier[tier].total += 1;
  if (RESPONDED_STATUSES.includes(a.status)) byTier[tier].responded += 1;
}
const tierLines = Object.entries(byTier)
  .map(([tier, d]) => `  ${tier}: ${d.total} application(s), response rate ${pct(d.responded, d.total)}`)
  .join('\n') || '  (none)';

// By company type
const byCompanyType = {};
for (const a of apps) {
  const ct = a.company_type || 'unknown';
  if (!byCompanyType[ct]) byCompanyType[ct] = { total: 0, responded: 0 };
  byCompanyType[ct].total += 1;
  if (RESPONDED_STATUSES.includes(a.status)) byCompanyType[ct].responded += 1;
}
const companyTypeLines = Object.entries(byCompanyType)
  .map(([ct, d]) => `  ${ct}: ${d.total} application(s), response rate ${pct(d.responded, d.total)}`)
  .join('\n') || '  (none)';

// Per-application list
const appLines = apps.map(a => {
  const days = Math.floor((now - new Date(a.created_at)) / (1000 * 60 * 60 * 24));
  return `  - ${a.role_title || '(untitled role)'} @ ${a.company_name || '(unknown company)'} ` +
    `| company_type: ${a.company_type || 'unknown'} ` +
    `| match tier: ${a.match_tier || 'unknown'} ` +
    `| match score: ${a.match_score ?? 'unknown'} ` +
    `| status: ${a.status} ` +
    `| ${days} day(s) ago`;
}).join('\n') || '  (none)';

const prompt = [
  '## Window',
  `Date range: ${weekStartStr} to ${todayStr} (last 4 weeks)`,
  `Total applications in window: ${n}`,
  `Minimum sample size reached (N >= ${MIN_N}): ${minNReached ? 'yes' : 'no'}`,
  '',
  '## Status breakdown',
  statusLines,
  '',
  '## Match score stats',
  `Average match score: ${avgScore ?? 'unknown'}`,
  'By match tier:',
  tierLines,
  '',
  '## Company type breakdown',
  companyTypeLines,
  '',
  '## Applications in window',
  appLines,
].join('\n');

return [{
  json: {
    n,
    min_n_reached: minNReached,
    week_start: weekStartStr,
    pattern_prompt: prompt,
  },
}];

const output = JSON.parse($input.item.json.text);
const prior = $('Prepare Pattern Detector Input').item.json;
return [{
  json: {
    ...prior,
    pattern_output: output,
    pattern_output_json: JSON.stringify(output),
    pattern_model_used: $input.item.json.model,
  },
}];

const item = $('Parse Pattern Detector Output').item.json;
const output = item.pattern_output;

const lines = [
  `*Weekly Reflection - week of ${item.week_start}*`,
  '',
  `Applications in window: ${item.n}`,
  '',
  output.summary,
];

if (item.min_n_reached) {
  if (output.patterns.length > 0) {
    lines.push('', 'Patterns:');
    for (const p of output.patterns) {
      lines.push(`- *${p.observation}* (${p.confidence} confidence)`);
      lines.push(`  Evidence: ${p.evidence}`);
      lines.push(`  Suggested action: ${p.suggested_action}`);
    }
  } else {
    lines.push('', 'No patterns cleared the evidence bar this week.');
  }
}

return [{ json: { slack_text: lines.join('\n') } }];
